const fs = require('fs');
const config = $input.first().json;

let transcript;
try {
  transcript = fs.readFileSync(config.transcript_path, 'utf8');
} catch (e) {
  throw new Error(`Cannot read transcript: ${e.message}`);
}

const v1Path = `/home/node/outputs/accounts/${config.account_id}/v1/memo.json`;
let v1Memo;
try {
  v1Memo = JSON.parse(fs.readFileSync(v1Path, 'utf8'));
} catch (e) {
  throw new Error(`Cannot read v1 memo at ${v1Path}: ${e.message}. Run Pipeline A first.`);
}

return [{
  json: {
    ...config,
    transcript,
    v1_memo: v1Memo,
    filename: config.transcript_path.split('/').pop(),
    company_name: v1Memo.company_name
  }
}];

const http = require('http');
const data = $input.first().json;

const prompt = `You are a data extraction assistant. Compare this ONBOARDING call transcript against the existing account memo and extract ONLY the fields that are NEW or CHANGED.

Existing v1 memo:
${JSON.stringify(data.v1_memo, null, 2).substring(0, 2000)}

Return ONLY a JSON object with fields that changed or were added. If a field is unchanged, do NOT include it. Include null for fields that should be cleared.

Onboarding Transcript:
${data.transcript.substring(0, 6000)}`;

const body = JSON.stringify({
  model: data.model,
  prompt: prompt,
  stream: false,
  options: { temperature: 0.1 }
});

// Parse URL manually (URL class not available in n8n sandbox)
const urlParts = data.ollama_url.replace('http://', '').split(':');
const hostname = urlParts[0];
const port = urlParts[1] ? parseInt(urlParts[1]) : 80;

const result = await new Promise((resolve, reject) => {
  const req = http.request({
    hostname: hostname,
    port: port,
    path: '/api/generate',
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    timeout: 120000
  }, (res) => {
    let responseData = '';
    res.on('data', chunk => responseData += chunk);
    res.on('end', () => {
      try {
        resolve(JSON.parse(responseData));
      } catch (e) {
        reject(new Error('Failed to parse Ollama response'));
      }
    });
  });
  req.on('error', reject);
  req.on('timeout', () => reject(new Error('Ollama request timed out')));
  req.write(body);
  req.end();
});

return [{ json: { ...data, ollama_response: result.response || '' } }];

const raw = $input.first().json;
const response = raw.ollama_response;

let delta;
try {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  delta = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  delta = {};
}

const v1 = raw.v1_memo || {};
const v2 = JSON.parse(JSON.stringify(v1));
const changelog = [];

for (const [key, newVal] of Object.entries(delta)) {
  const oldVal = v1[key];
  if (JSON.stringify(oldVal) !== JSON.stringify(newVal)) {
    changelog.push({ field: key, old_value: oldVal || null, new_value: newVal, reason: 'onboarding_override' });
  }
  if (newVal && typeof newVal === 'object' && !Array.isArray(newVal) && oldVal && typeof oldVal === 'object') {
    v2[key] = { ...oldVal, ...newVal };
  } else {
    v2[key] = newVal;
  }
}

return [{
  json: {
    account_id: raw.account_id,
    company_name: v1.company_name || '',
    v2_memo: v2,
    delta,
    changelog,
    changes_count: changelog.length
  }
}];

const data = $input.first().json;
const memo = data.v2_memo;
const account_id = data.account_id;

const company = memo.company_name || 'Unknown Company';
const contact = memo.contact_name || 'the team';
const industry = memo.industry || 'general business';
const challenges = (memo.current_challenges || []).join(', ') || 'general inquiries';
const services = (memo.services_of_interest || []).join(', ') || 'our services';
const specials = (memo.special_instructions || []).join('\n- ') || 'None';
const hours = memo.business_hours || {};
const bh = `${hours.days || 'Monday-Friday'}, ${hours.open || '9:00 AM'} - ${hours.close || '5:00 PM'}`;

const system_prompt = `You are Clara, an AI voice assistant for ${company}.

Company: ${company}
Industry: ${industry}
Primary Contact: ${contact}
Business Hours: ${bh}

Key Services: ${services}
Customer Challenges: ${challenges}
Special Instructions:
- ${specials}

During business hours:
- Answer calls professionally for ${company}
- Help with scheduling and service inquiries
- Collect caller name, phone, and reason for calling
- Transfer to ${contact} for complex issues

Outside business hours:
- Inform callers of business hours (${bh})
- Offer to take a message
- Handle emergencies per protocol

Critical Rules:
- Never fabricate information about ${company}
- Always confirm before transferring calls
- Be professional, friendly, and empathetic

This is v2 (updated after onboarding call with ${data.changes_count} changes applied).`;

const agent_spec = {
  agent_name: `${company} - Clara AI`,
  account_id,
  version: 'v2',
  system_prompt,
  voice_style: { tone: 'professional and friendly', pace: 'moderate', personality: 'helpful assistant' },
  source: 'onboarding_call',
  changes_from_v1: data.changes_count
};

return [{ json: { ...data, agent_spec } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const baseDir = `/home/node/outputs/accounts/${data.account_id}/v2`;

try {
  fs.mkdirSync(baseDir, { recursive: true });
  fs.writeFileSync(path.join(baseDir, 'memo.json'), JSON.stringify(data.v2_memo, null, 2));
  fs.writeFileSync(path.join(baseDir, 'agent_spec.json'), JSON.stringify(data.agent_spec, null, 2));
  fs.writeFileSync(path.join(baseDir, 'delta.json'), JSON.stringify(data.delta, null, 2));
  fs.writeFileSync(path.join(baseDir, 'changelog.json'), JSON.stringify({
    account_id: data.account_id,
    company: data.company_name,
    version_from: 'v1', version_to: 'v2',
    total_changes: data.changes_count,
    changes: data.changelog
  }, null, 2));

  const changelogDir = '/home/node/changelog';
  fs.mkdirSync(changelogDir, { recursive: true });
  let md = `# Changelog: ${data.company_name}\n\n`;
  md += `**Account ID:** ${data.account_id}\n`;
  md += `**Version:** v1 → v2\n`;
  md += `**Total Changes:** ${data.changes_count}\n\n`;
  md += `| Field | Old Value | New Value | Reason |\n|-------|-----------|-----------|--------|\n`;
  for (const c of data.changelog) {
    md += `| ${c.field} | ${JSON.stringify(c.old_value)} | ${JSON.stringify(c.new_value)} | ${c.reason} |\n`;
  }
  fs.writeFileSync(path.join(changelogDir, `${data.account_id}_changes.md`), md);

  return [{
    json: {
      status: 'SUCCESS',
      account_id: data.account_id,
      company: data.company_name,
      output_dir: baseDir,
      files_saved: ['memo.json', 'agent_spec.json', 'delta.json', 'changelog.json'],
      changes_applied: data.changes_count,
      message: `Pipeline B complete: ${data.changes_count} changes for ${data.company_name}`
    }
  }];
} catch (e) {
  return [{ json: { status: 'ERROR', error: e.message } }];
}
